192	void initialize_game() {
193	    std::cin >> N_pets_global;
194	    pets_global_state.resize(N_pets_global);
195	    for (int i = 0; i < N_pets_global; ++i) {
196	        pets_global_state[i].id = i;
197	        std::cin >> pets_global_state[i].pos.r >> pets_global_state[i].pos.c >> pets_global_state[i].type;
198	    }
199	
200	    std::cin >> M_humans_global;
201	    humans_global_state.resize(M_humans_global);
202	
203	    for(int r_grid=0; r_grid <= GRID_SIZE; ++r_grid) for(int c_grid=0; c_grid <= GRID_SIZE; ++c_grid) is_impassable_grid_static[r_grid][c_grid] = false;
204	    
205	    int base_strip_height = GRID_SIZE / M_humans_global;
206	    int remainder_heights = GRID_SIZE % M_humans_global;
207	    int current_r_start_coord = 1;
208	
209	    for (int i = 0; i < M_humans_global; ++i) {
210	        HumanInfo& human = humans_global_state[i];
211	        human.id = i;
212	        std::cin >> human.pos.r >> human.pos.c;
213	        
214	        int strip_h_for_this_human = base_strip_height + (i < remainder_heights ? 1 : 0);
215	        human.strip_r_start = current_r_start_coord;
216	        human.strip_r_end = human.strip_r_start + strip_h_for_this_human - 1;
217	        human.strip_r_end = std::min(human.strip_r_end, GRID_SIZE); 
218	        
219	        int actual_strip_h = human.strip_r_end - human.strip_r_start + 1;
220	        int actual_strip_w = GRID_SIZE; 
221	
222	        human.inner_safe_ul.r = human.strip_r_start + (actual_strip_h >= 3 ? 1 : 0);
223	        human.inner_safe_ul.c = 1 + (actual_strip_w >= 3 ? 1 : 0); 
224	        human.inner_safe_br.r = human.strip_r_end - (actual_strip_h >= 3 ? 1 : 0);
225	        human.inner_safe_br.c = GRID_SIZE - (actual_strip_w >= 3 ? 1 : 0);
226	        
227	        if (human.inner_safe_ul.r > human.inner_safe_br.r) human.inner_safe_br.r = human.inner_safe_ul.r;
228	        if (human.inner_safe_ul.c > human.inner_safe_br.c) human.inner_safe_br.c = human.inner_safe_ul.c;
229	        
230	        human.final_stand_pos = {
231	            human.inner_safe_ul.r + (human.inner_safe_br.r - human.inner_safe_ul.r) / 2,
232	            human.inner_safe_ul.c + (human.inner_safe_br.c - human.inner_safe_ul.c) / 2
233	        };
234	        human.final_stand_pos.r = std::max(human.inner_safe_ul.r, std::min(human.inner_safe_br.r, human.final_stand_pos.r));
235	        human.final_stand_pos.c = std::max(human.inner_safe_ul.c, std::min(human.inner_safe_br.c, human.final_stand_pos.c));
236	        if (!is_valid_point(human.final_stand_pos)) { 
237	            human.final_stand_pos = {human.strip_r_start, 1}; 
238	        }
239	
240	        human.assigned_wall_cells.clear();
241	        int r_s = human.strip_r_start;
242	        int r_e = human.strip_r_end;
243	
244	        if (i == 0) { 
245	            for (int c_coord = 1; c_coord <= GRID_SIZE; ++c_coord) human.assigned_wall_cells.push_back({r_s, c_coord});
246	        } else { 
247	            for (int c_coord = GRID_SIZE / 2 + 1; c_coord <= GRID_SIZE; ++c_coord) human.assigned_wall_cells.push_back({r_s, c_coord});
248	        }
249	        if (i == M_humans_global - 1) { 
250	            for (int c_coord = 1; c_coord <= GRID_SIZE; ++c_coord) human.assigned_wall_cells.push_back({r_e, c_coord});
251	        } else { 
252	            for (int c_coord = 1; c_coord <= GRID_SIZE / 2; ++c_coord) human.assigned_wall_cells.push_back({r_e, c_coord});
253	        }
254	        for (int r_mid = r_s + 1; r_mid <= r_e - 1; ++r_mid) {
255	             human.assigned_wall_cells.push_back({r_mid, 1});          
256	             human.assigned_wall_cells.push_back({r_mid, GRID_SIZE}); 
257	        }
258	        
259	        std::sort(human.assigned_wall_cells.begin(), human.assigned_wall_cells.end());
260	        human.assigned_wall_cells.erase(
261	            std::unique(human.assigned_wall_cells.begin(), human.assigned_wall_cells.end()),
262	            human.assigned_wall_cells.end()
263	        );
264	        current_r_start_coord = human.strip_r_end + 1; 
265	    }
266	}
