# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const Point DIRS[4] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
const char DIR_BUILD[4] = {'u', 'd', 'l', 'r'};
const char DIR_MOVE[4] = {'U', 'D', 'L', 'R'};

struct Pet {
    Point pos;
    int type;
};

struct Human {
    Point pos;
};

int N_pets, M_humans;
std::vector<Pet> pets;
std::vector<Human> humans;
bool walls[GRID_SIZE + 2][GRID_SIZE + 2];

bool valid(Point p) { return p.r >= 1 && p.r <= GRID_SIZE && p.c >= 1 && p.c <= GRID_SIZE; }
bool passable(Point p) { return valid(p) && !walls[p.r][p.c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

int bfs_distance(Point from, Point to) {
    if (from == to) return 0;
    if (!passable(from) || !passable(to)) return INF;
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    q.push(from);
    bfs_dist[from.r][from.c] = 0;
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            Point nxt = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (passable(nxt) && bfs_dist[nxt.r][nxt.c] == -1) {
                bfs_dist[nxt.r][nxt.c] = bfs_dist[cur.r][cur.c] + 1;
                if (nxt == to) return bfs_dist[nxt.r][nxt.c];
                q.push(nxt);
            }
        }
    }
    return INF;
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    if (!passable(from) || !passable(to)) return '.';
    memset(bfs_dist, -1, sizeof(bfs_dist));
    memset(bfs_parent, -1, sizeof(bfs_parent));
    std::queue<Point> q;
    q.push(from);
    bfs_dist[from.r][from.c] = 0;
    bool found = false;
    while (!q.empty() && !found) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            Point nxt = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (passable(nxt) && bfs_dist[nxt.r][nxt.c] == -1) {
                bfs_dist[nxt.r][nxt.c] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nxt.r][nxt.c] = cur;
                if (nxt == to) { found = true; break; }
                q.push(nxt);
            }
        }
    }
    if (!found) return '.';
    Point step = to;
    while (!(bfs_parent[step.r][step.c] == from)) {
        step = bfs_parent[step.r][step.c];
        if (step.r == -1) return '.';
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DIRS[d].r == step.r && from.c + DIRS[d].c == step.c)
            return DIR_MOVE[d];
    }
    return '.';
}

bool can_build_at(Point p) {
    if (!valid(p) || walls[p.r][p.c]) return false;
    for (auto& pet : pets) {
        if (pet.pos == p) return false;
        if (std::abs(pet.pos.r - p.r) + std::abs(pet.pos.c - p.c) == 1) return false;
    }
    for (auto& h : humans) {
        if (h.pos == p) return false;
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N_pets;
    pets.resize(N_pets);
    for (int i = 0; i < N_pets; i++)
        std::cin >> pets[i].pos.r >> pets[i].pos.c >> pets[i].type;

    std::cin >> M_humans;
    humans.resize(M_humans);
    for (int i = 0; i < M_humans; i++)
        std::cin >> humans[i].pos.r >> humans[i].pos.c;

    memset(walls, false, sizeof(walls));

    // Strategy: Build a horizontal wall to divide the grid.
    // Choose the row that maximizes the area of the side with fewer pets.
    // All humans cooperate to build this wall, then move to the safe side.

    // Evaluate candidate wall rows (row R means walls at cells (R,1..30))
    // The wall divides into: top region rows 1..R-1, bottom region rows R+1..30
    int best_wall_row = -1;
    int best_score = -1;
    bool best_go_top = true; // which side humans should go to

    for (int R = 3; R <= GRID_SIZE - 2; R++) {
        int pets_top = 0, pets_bot = 0, pets_on_wall = 0;
        for (auto& pet : pets) {
            if (pet.pos.r < R) pets_top++;
            else if (pet.pos.r > R) pets_bot++;
            else pets_on_wall++;
        }
        // Don't consider rows where a pet is sitting (can't build there)
        if (pets_on_wall > 0) continue;

        int area_top = (R - 1) * GRID_SIZE;
        int area_bot = (GRID_SIZE - R) * GRID_SIZE;

        // We want to go to the side with fewer pets and larger area
        // Score = area * 2^(-pets_on_that_side)
        double score_top = (double)area_top * std::pow(2.0, -(double)pets_top);
        double score_bot = (double)area_bot * std::pow(2.0, -(double)pets_bot);

        double chosen_score;
        bool go_top;
        if (score_top >= score_bot) {
            chosen_score = score_top;
            go_top = true;
        } else {
            chosen_score = score_bot;
            go_top = false;
        }

        if ((int)(chosen_score * 1000) > best_score) {
            best_score = (int)(chosen_score * 1000);
            best_wall_row = R;
            best_go_top = go_top;
        }
    }

    // Also evaluate vertical walls
    int best_wall_col = -1;
    int best_col_score = -1;
    bool best_go_left = true;

    for (int C = 3; C <= GRID_SIZE - 2; C++) {
        int pets_left = 0, pets_right = 0, pets_on_wall = 0;
        for (auto& pet : pets) {
            if (pet.pos.c < C) pets_left++;
            else if (pet.pos.c > C) pets_right++;
            else pets_on_wall++;
        }
        if (pets_on_wall > 0) continue;

        int area_left = GRID_SIZE * (C - 1);
        int area_right = GRID_SIZE * (GRID_SIZE - C);

        double score_left = (double)area_left * std::pow(2.0, -(double)pets_left);
        double score_right = (double)area_right * std::pow(2.0, -(double)pets_right);

        double chosen_score;
        bool go_left;
        if (score_left >= score_right) {
            chosen_score = score_left;
            go_left = true;
        } else {
            chosen_score = score_right;
            go_left = false;
        }

        if ((int)(chosen_score * 1000) > best_col_score) {
            best_col_score = (int)(chosen_score * 1000);
            best_wall_col = C;
            best_go_left = go_left;
        }
    }

    // Choose horizontal or vertical
    bool use_horizontal = (best_score >= best_col_score);

    // Build the wall cells list
    std::vector<Point> wall_cells;
    Point safe_center;

    if (use_horizontal) {
        for (int c = 1; c <= GRID_SIZE; c++)
            wall_cells.push_back({best_wall_row, c});
        if (best_go_top)
            safe_center = {best_wall_row / 2, GRID_SIZE / 2};
        else
            safe_center = {(best_wall_row + 1 + GRID_SIZE) / 2, GRID_SIZE / 2};
    } else {
        for (int r = 1; r <= GRID_SIZE; r++)
            wall_cells.push_back({r, best_wall_col});
        if (best_go_left)
            safe_center = {GRID_SIZE / 2, best_wall_col / 2};
        else
            safe_center = {GRID_SIZE / 2, (best_wall_col + 1 + GRID_SIZE) / 2};
    }

    // Phase tracking
    // Phase 0: Move to build positions and build primary wall
    // Phase 1: Move to safe side
    // Phase 2: Build secondary walls (perpendicular barriers to trap remaining pets)
    // Phase 3: Stay put

    // Assign wall segments to humans
    // Each human is responsible for building wall_cells[segment_start..segment_end]
    std::vector<int> human_segment_start(M_humans);
    std::vector<int> human_segment_end(M_humans);
    int cells_per_human = wall_cells.size() / M_humans;
    int extra = wall_cells.size() % M_humans;
    int idx = 0;
    for (int i = 0; i < M_humans; i++) {
        human_segment_start[i] = idx;
        int cnt = cells_per_human + (i < extra ? 1 : 0);
        human_segment_end[i] = idx + cnt - 1;
        idx += cnt;
    }

    // Track which wall cells are built
    std::vector<bool> wall_built(wall_cells.size(), false);

    // Also plan secondary walls: build a second barrier to trap pets on the unsafe side
    // After main wall is done, try to build perpendicular walls from edges
    std::vector<Point> secondary_walls;
    if (use_horizontal) {
        // Build walls on the safe side boundary to ensure no gaps
        // Actually, try to build a second horizontal wall to create a buffer zone
        int second_row = best_go_top ? best_wall_row - 2 : best_wall_row + 2;
        if (second_row >= 2 && second_row <= GRID_SIZE - 1) {
            for (int c = 1; c <= GRID_SIZE; c++)
                secondary_walls.push_back({second_row, c});
        }
    } else {
        int second_col = best_go_left ? best_wall_col - 2 : best_wall_col + 2;
        if (second_col >= 2 && second_col <= GRID_SIZE - 1) {
            for (int r = 1; r <= GRID_SIZE; r++)
                secondary_walls.push_back({r, second_col});
        }
    }

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M_humans, '.');

        // Check if primary wall is complete
        bool primary_done = true;
        for (int i = 0; i < (int)wall_cells.size(); i++) {
            if (!walls[wall_cells[i].r][wall_cells[i].c]) {
                primary_done = false;
                break;
            }
        }

        for (int h = 0; h < M_humans; h++) {
            Point pos = humans[h].pos;

            if (!primary_done) {
                // Find the closest unbuilt wall cell in this human's segment
                // If none available, help with other segments
                Point best_target = {-1, -1};
                int best_dist = INF;

                // First try own segment
                for (int i = human_segment_start[h]; i <= human_segment_end[h]; i++) {
                    if (walls[wall_cells[i].r][wall_cells[i].c]) continue;
                    int d = std::abs(pos.r - wall_cells[i].r) + std::abs(pos.c - wall_cells[i].c);
                    if (d < best_dist) {
                        best_dist = d;
                        best_target = wall_cells[i];
                    }
                }

                // If own segment done, help others
                if (best_target.r == -1) {
                    for (int i = 0; i < (int)wall_cells.size(); i++) {
                        if (walls[wall_cells[i].r][wall_cells[i].c]) continue;
                        int d = std::abs(pos.r - wall_cells[i].r) + std::abs(pos.c - wall_cells[i].c);
                        if (d < best_dist) {
                            best_dist = d;
                            best_target = wall_cells[i];
                        }
                    }
                }

                if (best_target.r == -1) {
                    // All walls built (shouldn't reach here since primary_done check)
                    actions[h] = '.';
                    continue;
                }

                // Check if we're adjacent to the target and can build
                bool built = false;
                for (int d = 0; d < 4; d++) {
                    if (pos.r + DIRS[d].r == best_target.r && pos.c + DIRS[d].c == best_target.c) {
                        if (can_build_at(best_target)) {
                            actions[h] = DIR_BUILD[d];
                            built = true;
                        }
                        break;
                    }
                }

                if (!built) {
                    // Move toward a position adjacent to the target wall cell
                    // Prefer positions on the safe side
                    Point best_stand = {-1, -1};
                    int best_stand_dist = INF;
                    for (int d = 0; d < 4; d++) {
                        Point stand = {best_target.r + DIRS[d].r, best_target.c + DIRS[d].c};
                        if (!passable(stand)) continue;
                        // Prefer standing on the safe side
                        bool on_safe_side = false;
                        if (use_horizontal) {
                            on_safe_side = best_go_top ? (stand.r < best_wall_row) : (stand.r > best_wall_row);
                        } else {
                            on_safe_side = best_go_left ? (stand.c < best_wall_col) : (stand.c > best_wall_col);
                        }
                        int sd = std::abs(pos.r - stand.r) + std::abs(pos.c - stand.c);
                        if (!on_safe_side) sd += 5; // penalty for unsafe side
                        if (sd < best_stand_dist) {
                            best_stand_dist = sd;
                            best_stand = stand;
                        }
                    }
                    if (best_stand.r != -1) {
                        char mv = move_toward(pos, best_stand);
                        actions[h] = mv;
                    }
                }
            } else {
                // Primary wall done. Check if we're on the safe side.
                bool on_safe = false;
                if (use_horizontal) {
                    on_safe = best_go_top ? (pos.r < best_wall_row) : (pos.r > best_wall_row);
                } else {
                    on_safe = best_go_left ? (pos.c < best_wall_col) : (pos.c > best_wall_col);
                }

                if (!on_safe) {
                    // Need to get to safe side - find a gap or built passage
                    // Since wall is complete, we might be stuck. Just stay.
                    // Actually try to find any opening
                    Point target_safe;
                    if (use_horizontal) {
                        target_safe = best_go_top ? Point{best_wall_row - 1, pos.c} : Point{best_wall_row + 1, pos.c};
                    } else {
                        target_safe = best_go_left ? Point{pos.r, best_wall_col - 1} : Point{pos.r, best_wall_col + 1};
                    }
                    if (passable(target_safe)) {
                        char mv = move_toward(pos, target_safe);
                        actions[h] = mv;
                    }
                } else {
                    // On safe side. Try building secondary walls or stay.
                    // Find nearest unbuilt secondary wall
                    Point best_sec = {-1, -1};
                    int best_sec_dist = INF;
                    for (auto& sw : secondary_walls) {
                        if (walls[sw.r][sw.c]) continue;
                        // Only build secondary walls on the safe side
                        bool sec_on_safe = false;
                        if (use_horizontal) {
                            sec_on_safe = best_go_top ? (sw.r < best_wall_row) : (sw.r > best_wall_row);
                        } else {
                            sec_on_safe = best_go_left ? (sw.c < best_wall_col) : (sw.c > best_wall_col);
                        }
                        if (!sec_on_safe) continue;
                        int d = std::abs(pos.r - sw.r) + std::abs(pos.c - sw.c);
                        if (d < best_sec_dist) {
                            best_sec_dist = d;
                            best_sec = sw;
                        }
                    }

                    if (best_sec.r != -1) {
                        bool built = false;
                        for (int d = 0; d < 4; d++) {
                            if (pos.r + DIRS[d].r == best_sec.r && pos.c + DIRS[d].c == best_sec.c) {
                                if (can_build_at(best_sec)) {
                                    actions[h] = DIR_BUILD[d];
                                    built = true;
                                }
                                break;
                            }
                        }
                        if (!built) {
                            // Move toward secondary wall build position
                            Point best_stand = {-1, -1};
                            int best_stand_dist = INF;
                            for (int d = 0; d < 4; d++) {
                                Point stand = {best_sec.r + DIRS[d].r, best_sec.c + DIRS[d].c};
                                if (!passable(stand)) continue;
                                int sd = std::abs(pos.r - stand.r) + std::abs(pos.c - stand.c);
                                if (sd < best_stand_dist) {
                                    best_stand_dist = sd;
                                    best_stand = stand;
                                }
                            }
                            if (best_stand.r != -1) {
                                actions[h] = move_toward(pos, best_stand);
                            }
                        }
                    }
                    // else: nothing to do, stay put
                }
            }
        }

        // Validate: ensure no two humans move to same cell, no move into wall being built
        std::vector<Point> built_this_turn;
        std::vector<Point> move_targets(M_humans, {-1, -1});

        for (int h = 0; h < M_humans; h++) {
            char a = actions[h];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == DIR_BUILD[d]) {
                        Point wp = {humans[h].pos.r + DIRS[d].r, humans[h].pos.c + DIRS[d].c};
                        if (valid(wp)) built_this_turn.push_back(wp);
                        break;
