#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <queue>
#include <cmath>
#include <limits>
#include <cstring>

constexpr int GRID_SIZE = 30;
constexpr int NUM_TURNS = 300;
constexpr int INF = std::numeric_limits<int>::max();

struct Point {
    int r, c;
    bool operator==(const Point& o) const { return r == o.r && c == o.c; }
    bool operator!=(const Point& o) const { return !(*this == o); }
};

const Point DIRS[4] = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};
const char DIR_BUILD[4] = {'u', 'd', 'l', 'r'};
const char DIR_MOVE[4] = {'U', 'D', 'L', 'R'};

struct Pet {
    Point pos;
    int type;
};

struct Human {
    Point pos;
};

int N_pets, M_humans;
std::vector<Pet> pets;
std::vector<Human> humans;
bool walls[GRID_SIZE + 2][GRID_SIZE + 2];

bool valid(Point p) { return p.r >= 1 && p.r <= GRID_SIZE && p.c >= 1 && p.c <= GRID_SIZE; }
bool passable(Point p) { return valid(p) && !walls[p.r][p.c]; }

int bfs_dist[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent[GRID_SIZE + 2][GRID_SIZE + 2];

int bfs_distance(Point from, Point to) {
    if (from == to) return 0;
    if (!passable(from) || !passable(to)) return INF;
    memset(bfs_dist, -1, sizeof(bfs_dist));
    std::queue<Point> q;
    q.push(from);
    bfs_dist[from.r][from.c] = 0;
    while (!q.empty()) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            Point nxt = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (passable(nxt) && bfs_dist[nxt.r][nxt.c] == -1) {
                bfs_dist[nxt.r][nxt.c] = bfs_dist[cur.r][cur.c] + 1;
                if (nxt == to) return bfs_dist[nxt.r][nxt.c];
                q.push(nxt);
            }
        }
    }
    return INF;
}

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    if (!passable(from) || !passable(to)) return '.';
    memset(bfs_dist, -1, sizeof(bfs_dist));
    memset(bfs_parent, -1, sizeof(bfs_parent));
    std::queue<Point> q;
    q.push(from);
    bfs_dist[from.r][from.c] = 0;
    bool found = false;
    while (!q.empty() && !found) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            Point nxt = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (passable(nxt) && bfs_dist[nxt.r][nxt.c] == -1) {
                bfs_dist[nxt.r][nxt.c] = bfs_dist[cur.r][cur.c] + 1;
                bfs_parent[nxt.r][nxt.c] = cur;
                if (nxt == to) { found = true; break; }
                q.push(nxt);
            }
        }
    }
    if (!found) return '.';
    Point step = to;
    while (!(bfs_parent[step.r][step.c] == from)) {
        step = bfs_parent[step.r][step.c];
        if (step.r == -1) return '.';
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DIRS[d].r == step.r && from.c + DIRS[d].c == step.c)
            return DIR_MOVE[d];
    }
    return '.';
}

bool can_build_at(Point p) {
    if (!valid(p) || walls[p.r][p.c]) return false;
    for (auto& pet : pets) {
        if (pet.pos == p) return false;
        if (std::abs(pet.pos.r - p.r) + std::abs(pet.pos.c - p.c) == 1) return false;
    }
    for (auto& h : humans) {
        if (h.pos == p) return false;
    }
    return true;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N_pets;
    pets.resize(N_pets);
    for (int i = 0; i < N_pets; i++)
        std::cin >> pets[i].pos.r >> pets[i].pos.c >> pets[i].type;

    std::cin >> M_humans;
    humans.resize(M_humans);
    for (int i = 0; i < M_humans; i++)
        std::cin >> humans[i].pos.r >> humans[i].pos.c;

    memset(walls, false, sizeof(walls));

    // Strategy: Build a horizontal wall to divide the grid.
    // Choose the row that maximizes the area of the side with fewer pets.
    // All humans cooperate to build this wall, then move to the safe side.

    // Evaluate candidate wall rows (row R means walls at cells (R,1..30))
    // The wall divides into: top region rows 1..R-1, bottom region rows R+1..30
    int best_wall_row = -1;
    int best_score = -1;
    bool best_go_top = true; // which side humans should go to

    for (int R = 3; R <= GRID_SIZE - 2; R++) {
        int pets_top = 0, pets_bot = 0, pets_on_wall = 0;
        for (auto& pet : pets) {
            if (pet.pos.r < R) pets_top++;
            else if (pet.pos.r > R) pets_bot++;
            else pets_on_wall++;
        }
        // Don't consider rows where a pet is sitting (can't build there)
        if (pets_on_wall > 0) continue;

        int area_top = (R - 1) * GRID_SIZE;
        int area_bot = (GRID_SIZE - R) * GRID_SIZE;

        // We want to go to the side with fewer pets and larger area
        // Score = area * 2^(-pets_on_that_side)
        double score_top = (double)area_top * std::pow(2.0, -(double)pets_top);
        double score_bot = (double)area_bot * std::pow(2.0, -(double)pets_bot);

        double chosen_score;
        bool go_top;
        if (score_top >= score_bot) {
            chosen_score = score_top;
            go_top = true;
        } else {
            chosen_score = score_bot;
            go_top = false;
        }

        if ((int)(chosen_score * 1000) > best_score) {
            best_score = (int)(chosen_score * 1000);
            best_wall_row = R;
            best_go_top = go_top;
        }
    }

    // Also evaluate vertical walls
    int best_wall_col = -1;
    int best_col_score = -1;
    bool best_go_left = true;

    for (int C = 3; C <= GRID_SIZE - 2; C++) {
        int pets_left = 0, pets_right = 0, pets_on_wall = 0;
        for (auto& pet : pets) {
            if (pet.pos.c < C) pets_left++;
            else if (pet.pos.c > C) pets_right++;
            else pets_on_wall++;
        }
        if (pets_on_wall > 0) continue;

        int area_left = GRID_SIZE * (C - 1);
        int area_right = GRID_SIZE * (GRID_SIZE - C);

        double score_left = (double)area_left * std::pow(2.0, -(double)pets_left);
        double score_right = (double)area_right * std::pow(2.0, -(double)pets_right);

        double chosen_score;
        bool go_left;
        if (score_left >= score_right) {
            chosen_score = score_left;
            go_left = true;
        } else {
            chosen_score = score_right;
            go_left = false;
        }

        if ((int)(chosen_score * 1000) > best_col_score) {
            best_col_score = (int)(chosen_score * 1000);
            best_wall_col = C;
            best_go_left = go_left;
        }
