}

struct WallPlan {
    bool horizontal; // true = horizontal wall, false = vertical
    int wall_idx;    // row or column index of the wall
    bool go_first;   // go to side with smaller coordinate (top or left)
    double expected_score;
};

WallPlan choose_wall() {
    WallPlan best;
    best.expected_score = -1;

    // Evaluate horizontal walls
    for (int R = 2; R <= GRID_SIZE - 1; R++) {
