        bool go_top;
        if (eval_top >= eval_bot) { chosen = eval_top; go_top = true; }
        else { chosen = eval_bot; go_top = false; }

        if (chosen > best.expected_score) {
            best.expected_score = chosen;
            best.horizontal = true;
            best.wall_idx = R;
            best.go_first = go_top;
        }
    }

