        int pets_left = 0, pets_right = 0;
        for (auto& pet : pets) {
            if (pet.pos.c == C) continue; // skip
            if (pet.pos.c < C) pets_left++;
            else pets_right++;
        }

        int area_left = GRID_SIZE * (C - 1);
        int area_right = GRID_SIZE * (GRID_SIZE - C);

        int humans_left = 0, humans_right = 0;
        for (auto& h : humans) {
            if (h.pos.c < C) humans_left++;
            else if (h.pos.c > C) humans_right++;
            else humans_left++;
        }

        double score_left = (double)area_left / 900.0 * std::pow(2.0, -(double)pets_left);
        double score_right = (double)area_right / 900.0 * std::pow(2.0, -(double)pets_right);

        double eval_left = score_left;
        double eval_right = score_right;

        if (humans_left < M_humans / 2) eval_left *= 0.7;
        if (humans_right < M_humans / 2) eval_right *= 0.7;

        double chosen;
        bool go_left;
        if (eval_left >= eval_right) { chosen = eval_left; go_left = true; }
        else { chosen = eval_right; go_left = false; }

        if (chosen > best.expected_score) {
            best.expected_score = chosen;
            best.horizontal = false;
            best.wall_idx = C;
            best.go_first = go_left;
        }
    }

