    if (plan.horizontal) {
        int dr = plan.go_first ? -1 : 1;
        Point p = {wall_cell.r + dr, wall_cell.c};
        if (valid(p)) return p;
    } else {
        int dc = plan.go_first ? -1 : 1;
        Point p = {wall_cell.r, wall_cell.c + dc};
        if (valid(p)) return p;
    }
    return {-1, -1};
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N_pets;
    pets.resize(N_pets);
    for (int i = 0; i < N_pets; i++)
        std::cin >> pets[i].pos.r >> pets[i].pos.c >> pets[i].type;

    std::cin >> M_humans;
    humans.resize(M_humans);
    for (int i = 0; i < M_humans; i++)
        std::cin >> humans[i].pos.r >> humans[i].pos.c;

    memset(walls, false, sizeof(walls));

    WallPlan plan = choose_wall();

    // Build the wall cells list
    std::vector<Point> wall_cells;
    if (plan.horizontal) {
        for (int c = 1; c <= GRID_SIZE; c++)
            wall_cells.push_back({plan.wall_idx, c});
    } else {
        for (int r = 1; r <= GRID_SIZE; r++)
            wall_cells.push_back({r, plan.wall_idx});
    }

    // Phase 0: First get all humans to safe side
    // Phase 1: Build wall from the safe side
    // Phase 2: Stay put

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M_humans, '.');

        // Check wall completion
        int unbuilt = 0;
        for (auto& wc : wall_cells) {
            if (!walls[wc.r][wc.c]) unbuilt++;
        }
        bool wall_done = (unbuilt == 0);

        for (int h = 0; h < M_humans; h++) {
            Point pos = humans[h].pos;
            bool on_safe = is_on_safe_side(pos, plan);

            if (!wall_done) {
                if (!on_safe) {
                    // Move toward safe side (cross the wall line)
                    Point target;
                    if (plan.horizontal) {
                        int target_r = plan.go_first ? plan.wall_idx - 1 : plan.wall_idx + 1;
                        target = {target_r, pos.c};
                    } else {
                        int target_c = plan.go_first ? plan.wall_idx - 1 : plan.wall_idx + 1;
                        target = {pos.r, target_c};
                    }
                    if (passable(target)) {
                        char mv = move_toward(pos, target);
                        actions[h] = mv;
                    }
                } else {
                    // On safe side: find nearest unbuilt wall cell and build from safe side
                    Point best_target = {-1, -1};
                    int best_dist = INF;

                    for (auto& wc : wall_cells) {
                        if (walls[wc.r][wc.c]) continue;
                        // The stand position is on the safe side adjacent to wall cell
                        Point stand = get_safe_adjacent(wc, plan);
                        if (stand.r == -1 || !passable(stand)) continue;
                        int d = std::abs(pos.r - stand.r) + std::abs(pos.c - stand.c);
                        if (d < best_dist) {
                            best_dist = d;
                            best_target = wc;
                        }
                    }

                    if (best_target.r == -1) {
                        actions[h] = '.';
                        continue;
                    }

                    Point stand = get_safe_adjacent(best_target, plan);

                    if (pos == stand) {
                        // Try to build
                        if (can_build_at(best_target)) {
                            for (int d = 0; d < 4; d++) {
                                if (pos.r + DIRS[d].r == best_target.r && pos.c + DIRS[d].c == best_target.c) {
                                    actions[h] = DIR_BUILD[d];
                                    break;
                                }
                            }
                        }
                    } else {
                        // Move toward stand position
                        actions[h] = move_toward(pos, stand);
                    }
                }
            } else {
                // Wall is done. Stay put if on safe side.
                if (!on_safe) {
                    // Try to get to safe side (shouldn't happen normally)
                    actions[h] = '.';
                }
            }
        }

        // Validate actions
        std::vector<Point> built_this_turn;
        std::vector<Point> move_targets(M_humans, {-1, -1});

        for (int h = 0; h < M_humans; h++) {
            char a = actions[h];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == DIR_BUILD[d]) {
                        Point wp = {humans[h].pos.r + DIRS[d].r, humans[h].pos.c + DIRS[d].c};
                        if (valid(wp) && can_build_at(wp)) {
                            built_this_turn.push_back(wp);
                        } else {
                            actions[h] = '.';
                        }
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == DIR_MOVE[d]) {
                        Point mp = {humans[h].pos.r + DIRS[d].r, humans[h].pos.c + DIRS[d].c};
                        if (valid(mp) && passable(mp)) {
                            move_targets[h] = mp;
                        } else {
                            actions[h] = '.';
                        }
                        break;
                    }
                }
            }
        }

        // Check move conflicts with walls being built this turn
        for (int h = 0; h < M_humans; h++) {
            if (move_targets[h].r == -1) continue;
            for (auto& bw : built_this_turn) {
                if (move_targets[h] == bw) {
                    actions[h] = '.';
                    move_targets[h] = {-1, -1};
                    break;
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply wall builds
        for (int h = 0; h < M_humans; h++) {
            char a = actions[h];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == DIR_BUILD[d]) {
                        Point wp = {humans[h].pos.r + DIRS[d].r, humans[h].pos.c + DIRS[d].c};
                        if (valid(wp)) walls[wp.r][wp.c] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == DIR_MOVE[d]) {
                        Point np = {humans[h].pos.r + DIRS[d].r, humans[h].pos.c + DIRS[d].c};
                        if (valid(np) && !walls[np.r][np.c]) {
                            humans[h].pos = np;
                        }
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N_pets; i++) {
            std::string pm;
            std::cin >> pm;
            if (pm == ".") continue;
            for (char c : pm) {
                for (int d = 0; d < 4; d++) {
                    if (c == DIR_MOVE[d]) {
                        pets[i].pos.r += DIRS[d].r;
                        pets[i].pos.c += DIRS[d].c;
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
# EVOLVE-BLOCK-END

