bool can_build_at(Point p) {
    if (!valid(p) || walls[p.r][p.c]) return false;
    for (auto& pet : pets) {
        if (pet.pos == p) return false;
        if (std::abs(pet.pos.r - p.r) + std::abs(pet.pos.c - p.c) == 1) return false;
