            if (sz_r > GRID_SIZE || sz_c > GRID_SIZE) continue;

            for (int r1 = 1; r1 <= GRID_SIZE - sz_r + 1; r1 += 2) {
                for (int c1 = 1; c1 <= GRID_SIZE - sz_c + 1; c1 += 2) {
                    int r2 = r1 + sz_r - 1;
                    int c2 = c1 + sz_c - 1;
                    if (r2 > GRID_SIZE || c2 > GRID_SIZE) continue;

                    Rect rect = {r1, c1, r2, c2};
                    int interior_area = (r2 - r1 - 1) * (c2 - c1 - 1);
                    int pets_in = count_pets_inside(rect);
                    int pets_on_boundary = 0;
                    for (auto& pet : pets) {
                        if (point_on_boundary(pet.pos, rect)) pets_on_boundary++;
