bool walls[GRID_SIZE + 2][GRID_SIZE + 2];

bool valid(Point p) { return p.r >= 1 && p.r <= GRID_SIZE && p.c >= 1 && p.c <= GRID_SIZE; }
bool passable(Point p) { return valid(p) && !walls[p.r][p.c]; }

int bfs_dist_arr[GRID_SIZE + 2][GRID_SIZE + 2];
Point bfs_parent_arr[GRID_SIZE + 2][GRID_SIZE + 2];

char move_toward(Point from, Point to) {
    if (from == to) return '.';
    if (!valid(from) || !valid(to)) return '.';
    if (!passable(from)) return '.';

    memset(bfs_dist_arr, -1, sizeof(bfs_dist_arr));
    std::queue<Point> q;
    q.push(from);
    bfs_dist_arr[from.r][from.c] = 0;
    bfs_parent_arr[from.r][from.c] = {-1, -1};
    bool found = false;

    while (!q.empty() && !found) {
        Point cur = q.front(); q.pop();
        for (int d = 0; d < 4; d++) {
            Point nxt = {cur.r + DIRS[d].r, cur.c + DIRS[d].c};
            if (valid(nxt) && passable(nxt) && bfs_dist_arr[nxt.r][nxt.c] == -1) {
                bfs_dist_arr[nxt.r][nxt.c] = bfs_dist_arr[cur.r][cur.c] + 1;
                bfs_parent_arr[nxt.r][nxt.c] = cur;
                if (nxt == to) { found = true; break; }
                q.push(nxt);
            }
        }
    }
    if (!found) return '.';

    Point step = to;
    while (!(bfs_parent_arr[step.r][step.c] == from)) {
        step = bfs_parent_arr[step.r][step.c];
        if (step.r == -1) return '.';
    }
    for (int d = 0; d < 4; d++) {
        if (from.r + DIRS[d].r == step.r && from.c + DIRS[d].c == step.c)
            return DIR_MOVE[d];
    }
    return '.';
}

bool can_build_at(Point p) {
    if (!valid(p) || walls[p.r][p.c]) return false;
    for (auto& pet : pets) {
        if (pet.pos == p) return false;
        if (std::abs(pet.pos.r - p.r) + std::abs(pet.pos.c - p.c) == 1) return false;
    }
    for (auto& h : humans) {
        if (h.pos == p) return false;
    }
    return true;
}

struct Rect {
    int r1, c1, r2, c2; // top-left to bottom-right (wall boundary inclusive)
};

bool point_inside_rect(Point p, const Rect& rect) {
    return p.r > rect.r1 && p.r < rect.r2 && p.c > rect.c1 && p.c < rect.c2;
}

bool point_on_boundary(Point p, const Rect& rect) {
    if (p.r == rect.r1 || p.r == rect.r2) {
        return p.c >= rect.c1 && p.c <= rect.c2;
    }
    if (p.c == rect.c1 || p.c == rect.c2) {
        return p.r >= rect.r1 && p.r <= rect.r2;
    }
    return false;
}

std::vector<Point> get_boundary_cells(const Rect& rect) {
    std::vector<Point> cells;
    for (int c = rect.c1; c <= rect.c2; c++) {
        cells.push_back({rect.r1, c});
        cells.push_back({rect.r2, c});
    }
    for (int r = rect.r1 + 1; r < rect.r2; r++) {
        cells.push_back({r, rect.c1});
        cells.push_back({r, rect.c2});
    }
    return cells;
}

int count_pets_inside(const Rect& rect) {
    int count = 0;
    for (auto& pet : pets) {
        if (point_inside_rect(pet.pos, rect)) count++;
    }
    return count;
}

Rect choose_enclosure() {
    // Try different rectangle sizes and positions
    // Target: large interior with few initial pets nearby
    // Interior = (r2-r1-1) × (c2-c1-1)

    int best_score = -1000000;
    Rect best = {1, 1, GRID_SIZE, GRID_SIZE};

    // Try various sizes
    std::vector<int> sizes = {10, 12, 14, 16, 18};

    for (int sz_r : sizes) {
        for (int sz_c : sizes) {
            if (sz_r > GRID_SIZE || sz_c > GRID_SIZE) continue;

            for (int r1 = 1; r1 <= GRID_SIZE - sz_r + 1; r1 += 2) {
                for (int c1 = 1; c1 <= GRID_SIZE - sz_c + 1; c1 += 2) {
                    int r2 = r1 + sz_r - 1;
                    int c2 = c1 + sz_c - 1;
                    if (r2 > GRID_SIZE || c2 > GRID_SIZE) continue;

                    Rect rect = {r1, c1, r2, c2};
                    int interior_area = (r2 - r1 - 1) * (c2 - c1 - 1);
                    int pets_in = count_pets_inside(rect);
                    int pets_on_boundary = 0;
                    for (auto& pet : pets) {
                        if (point_on_boundary(pet.pos, rect)) pets_on_boundary++;
                    }

                    // Score: want large area with few pets inside
                    // Also consider distance of humans to the interior
                    int total_human_dist = 0;
                    Point center = {(r1 + r2) / 2, (c1 + c2) / 2};
                    for (auto& h : humans) {
                        total_human_dist += std::abs(h.pos.r - center.r) + std::abs(h.pos.c - center.c);
                    }

                    // Perimeter to build
                    int perimeter = 2 * (sz_r + sz_c) - 4;

                    int score = interior_area * 100
                               - pets_in * 5000
                               - pets_on_boundary * 2000
                               - total_human_dist * 10
                               - perimeter * 5;

                    if (score > best_score) {
                        best_score = score;
                        best = rect;
                    }
                }
            }
        }
    }

    return best;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    std::cin >> N_pets;
    pets.resize(N_pets);
    for (int i = 0; i < N_pets; i++)
        std::cin >> pets[i].pos.r >> pets[i].pos.c >> pets[i].type;

    std::cin >> M_humans;
    humans.resize(M_humans);
    for (int i = 0; i < M_humans; i++)
        std::cin >> humans[i].pos.r >> humans[i].pos.c;

    memset(walls, false, sizeof(walls));

    Rect enclosure = choose_enclosure();
    std::vector<Point> boundary = get_boundary_cells(enclosure);
    Point center = {(enclosure.r1 + enclosure.r2) / 2, (enclosure.c1 + enclosure.c2) / 2};

    // Phases:
    // 1. All humans move inside the enclosure
    // 2. Build boundary walls from inside (human inside, builds outward toward boundary)
    // 3. Stay put

    // Assign spread-out positions inside for humans
    std::vector<Point> human_targets(M_humans);
    {
        int interior_h = enclosure.r2 - enclosure.r1 - 1;
        int interior_w = enclosure.c2 - enclosure.c1 - 1;
        for (int i = 0; i < M_humans; i++) {
            // Spread humans along the interior perimeter (1 cell inside the boundary)
            // so they can build boundary walls
            int pos_in_perim = i * (2 * (interior_h + interior_w)) / M_humans;
            int r, c;
            if (pos_in_perim < interior_w) {
                r = enclosure.r1 + 1;
                c = enclosure.c1 + 1 + pos_in_perim;
            } else if (pos_in_perim < interior_w + interior_h) {
                r = enclosure.r1 + 1 + (pos_in_perim - interior_w);
                c = enclosure.c2 - 1;
            } else if (pos_in_perim < 2 * interior_w + interior_h) {
                r = enclosure.r2 - 1;
                c = enclosure.c2 - 1 - (pos_in_perim - interior_w - interior_h);
            } else {
                r = enclosure.r2 - 1 - (pos_in_perim - 2 * interior_w - interior_h);
                c = enclosure.c1 + 1;
            }
            r = std::max(enclosure.r1 + 1, std::min(enclosure.r2 - 1, r));
            c = std::max(enclosure.c1 + 1, std::min(enclosure.c2 - 1, c));
            human_targets[i] = {r, c};
        }
    }

    for (int turn = 0; turn < NUM_TURNS; turn++) {
        std::string actions(M_humans, '.');

        // Check how many boundary walls still need building
        int unbuilt = 0;
        for (auto& bc : boundary) {
            if (!walls[bc.r][bc.c]) unbuilt++;
        }
        bool enclosure_done = (unbuilt == 0);

        for (int h = 0; h < M_humans; h++) {
            Point pos = humans[h].pos;
            bool inside = point_inside_rect(pos, enclosure);

            if (enclosure_done) {
                // Just stay put
                actions[h] = '.';
                continue;
            }

            if (!inside) {
                // Move toward interior
                // Target: the interior center or assigned position
                Point target = human_targets[h];
                // But if target is walled off, try center
                if (walls[target.r][target.c]) target = center;
                char mv = move_toward(pos, target);
                if (mv == '.') {
                    // Try center directly
                    mv = move_toward(pos, center);
                }
                actions[h] = mv;
            } else {
                // Inside: try to build a nearby boundary wall
                // Find nearest unbuilt boundary cell that we can build from inside
                Point best_wall = {-1, -1};
                int best_dist = INF;
                Point best_stand = {-1, -1};

                for (auto& bc : boundary) {
                    if (walls[bc.r][bc.c]) continue;

                    // Find a stand position inside the enclosure adjacent to this boundary cell
                    for (int d = 0; d < 4; d++) {
                        Point stand = {bc.r + DIRS[d].r, bc.c + DIRS[d].c};
                        if (!valid(stand) || !passable(stand)) continue;
                        if (!point_inside_rect(stand, enclosure)) continue;

                        int dist = std::abs(pos.r - stand.r) + std::abs(pos.c - stand.c);
                        if (dist < best_dist) {
                            best_dist = dist;
                            best_wall = bc;
                            best_stand = stand;
                        }
                    }
                }

                if (best_wall.r == -1) {
                    actions[h] = '.';
                    continue;
                }

                if (pos == best_stand) {
                    // Try to build
                    if (can_build_at(best_wall)) {
                        for (int d = 0; d < 4; d++) {
                            if (pos.r + DIRS[d].r == best_wall.r && pos.c + DIRS[d].c == best_wall.c) {
                                actions[h] = DIR_BUILD[d];
                                break;
                            }
                        }
                    } else {
                        // Can't build here (pet nearby), try another wall
                        Point alt_wall = {-1, -1};
                        int alt_dist = INF;
                        for (auto& bc : boundary) {
                            if (walls[bc.r][bc.c]) continue;
                            if (bc == best_wall) continue;
                            for (int d = 0; d < 4; d++) {
                                Point stand = {bc.r + DIRS[d].r, bc.c + DIRS[d].c};
                                if (!valid(stand) || !passable(stand)) continue;
                                if (!point_inside_rect(stand, enclosure)) continue;
                                if (!(stand == pos)) continue;
                                // We're already at this stand position
                                if (can_build_at(bc)) {
                                    int dist = 0;
                                    if (dist < alt_dist) {
                                        alt_dist = dist;
                                        alt_wall = bc;
                                    }
                                }
                            }
                        }
                        if (alt_wall.r != -1) {
                            for (int d = 0; d < 4; d++) {
                                if (pos.r + DIRS[d].r == alt_wall.r && pos.c + DIRS[d].c == alt_wall.c) {
                                    actions[h] = DIR_BUILD[d];
                                    break;
                                }
                            }
                        }
                        // else just wait
                    }
                } else {
                    // Move toward the stand position
                    actions[h] = move_toward(pos, best_stand);
                }
            }
        }

        // Validate actions
        std::vector<Point> built_this_turn;
        std::vector<Point> move_targets(M_humans, {-1, -1});

        for (int h = 0; h < M_humans; h++) {
            char a = actions[h];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == DIR_BUILD[d]) {
                        Point wp = {humans[h].pos.r + DIRS[d].r, humans[h].pos.c + DIRS[d].c};
                        if (valid(wp) && can_build_at(wp)) {
                            built_this_turn.push_back(wp);
                        } else {
                            actions[h] = '.';
                        }
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == DIR_MOVE[d]) {
                        Point mp = {humans[h].pos.r + DIRS[d].r, humans[h].pos.c + DIRS[d].c};
                        if (valid(mp) && passable(mp)) {
                            move_targets[h] = mp;
                        } else {
                            actions[h] = '.';
                        }
                        break;
                    }
                }
            }
        }

        // Check move conflicts with walls being built this turn
        for (int h = 0; h < M_humans; h++) {
            if (move_targets[h].r == -1) continue;
            for (auto& bw : built_this_turn) {
                if (move_targets[h] == bw) {
                    actions[h] = '.';
                    move_targets[h] = {-1, -1};
                    break;
                }
            }
        }

        std::cout << actions << std::endl;

        // Apply actions
        for (int h = 0; h < M_humans; h++) {
            char a = actions[h];
            if (a == 'u' || a == 'd' || a == 'l' || a == 'r') {
                for (int d = 0; d < 4; d++) {
                    if (a == DIR_BUILD[d]) {
                        Point wp = {humans[h].pos.r + DIRS[d].r, humans[h].pos.c + DIRS[d].c};
                        if (valid(wp)) walls[wp.r][wp.c] = true;
                        break;
                    }
                }
            } else if (a == 'U' || a == 'D' || a == 'L' || a == 'R') {
                for (int d = 0; d < 4; d++) {
                    if (a == DIR_MOVE[d]) {
                        Point np = {humans[h].pos.r + DIRS[d].r, humans[h].pos.c + DIRS[d].c};
                        if (valid(np) && !walls[np.r][np.c]) {
                            humans[h].pos = np;
                        }
                        break;
                    }
                }
            }
        }

        // Read pet movements
        for (int i = 0; i < N_pets; i++) {
            std::string pm;
            std::cin >> pm;
            if (pm == ".") continue;
            for (char c : pm) {
                for (int d = 0; d < 4; d++) {
                    if (c == DIR_MOVE[d]) {
                        pets[i].pos.r += DIRS[d].r;
                        pets[i].pos.c += DIRS[d].c;
                        break;
                    }
                }
            }
        }
    }

    return 0;
}
